-- BEGIN supabase/migrations/20260706_consolidate_save_routine_rpc.sql

-- Consolidates the same-day rewrites of the routine-saving RPC into one canonical,
-- idempotent migration. Replaces (and supersedes):
--   - 20260705_save_ai_routine_rpc.sql
--   - 20260705_atomic_routine_save.sql
--   - 20260705_save_routine_transaction.sql
-- Those three files rewrote public.save_routine_with_exercises / public.save_ai_routine
-- three times on the same day with drifting signatures. This migration reflects the
-- final, correct state (equivalent to 20260705_save_routine_transaction.sql) and is
-- safe to run regardless of which of the three prior migrations already ran in a given
-- environment: it drops any known prior signature before recreating the functions, since
-- PostgreSQL does not allow CREATE OR REPLACE FUNCTION to rename input parameters.
-- Requires the exercises_normalized_identity_idx unique index from
-- 20260705_harden_exercise_deduplication.sql.

begin;

drop function if exists public.save_routine_with_exercises(text, text, jsonb);
drop function if exists public.save_ai_routine(jsonb);

create function public.save_routine_with_exercises(
  routine_title text,
  routine_description text,
  exercises_payload jsonb
)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  new_routine_id uuid;
  exercise_payload jsonb;
  exercise_id uuid;
  exercise_name text;
  exercise_target_muscle text;
  exercise_equipment text;
  exercise_order integer := 0;
  current_user_id uuid := auth.uid();
begin
  if current_user_id is null then
    raise exception 'Debe iniciar sesión para guardar rutinas.';
  end if;

  if routine_title is null or btrim(routine_title) = '' then
    raise exception 'El título de la rutina es obligatorio.';
  end if;

  if exercises_payload is null or jsonb_typeof(exercises_payload) <> 'array' or jsonb_array_length(exercises_payload) = 0 then
    raise exception 'La rutina debe incluir al menos un ejercicio.';
  end if;

  insert into public.routines (user_id, title, description)
  values (current_user_id, btrim(routine_title), nullif(btrim(coalesce(routine_description, '')), ''))
  returning id into new_routine_id;

  for exercise_payload in select value from jsonb_array_elements(exercises_payload)
  loop
    exercise_order := exercise_order + 1;
    exercise_name := btrim(coalesce(exercise_payload->>'name', ''));
    exercise_target_muscle := btrim(coalesce(exercise_payload->>'targetMuscle', ''));
    exercise_equipment := btrim(coalesce(exercise_payload->>'equipment', ''));

    if exercise_name = '' then
      raise exception 'El ejercicio % no tiene nombre.', exercise_order;
    end if;

    select id into exercise_id
    from public.exercises
    where lower(btrim(name)) = lower(btrim(exercise_name))
      and lower(btrim(target_muscle)) = lower(btrim(exercise_target_muscle))
      and lower(btrim(equipment)) = lower(btrim(exercise_equipment))
    limit 1;

    if exercise_id is null then
      begin
        insert into public.exercises (name, target_muscle, equipment)
        values (exercise_name, exercise_target_muscle, exercise_equipment)
        returning id into exercise_id;
      exception when unique_violation then
        select id into exercise_id
        from public.exercises
        where lower(btrim(name)) = lower(btrim(exercise_name))
          and lower(btrim(target_muscle)) = lower(btrim(exercise_target_muscle))
          and lower(btrim(equipment)) = lower(btrim(exercise_equipment))
        limit 1;
      end;
    end if;

    if exercise_id is null then
      raise exception 'No se pudo crear o reutilizar el ejercicio %.', exercise_name;
    end if;

    insert into public.routine_exercises (
      routine_id,
      exercise_id,
      order_index,
      target_sets,
      target_reps,
      notes
    )
    values (
      new_routine_id,
      exercise_id,
      coalesce((exercise_payload->>'orderIndex')::integer, exercise_order),
      nullif(exercise_payload->>'targetSets', '')::integer,
      nullif(exercise_payload->>'targetReps', ''),
      nullif(exercise_payload->>'notes', '')
    );
  end loop;

  return new_routine_id;
end;
$$;

-- Compatibility wrapper for the current dashboard payload shape (Spanish keys from Gemini).
create function public.save_ai_routine(p_routine jsonb)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  exercises_payload jsonb;
begin
  if p_routine is null or jsonb_typeof(p_routine) <> 'object' then
    raise exception 'Payload de rutina inválido.';
  end if;

  select coalesce(jsonb_agg(
    jsonb_build_object(
      'orderIndex', exercise_order,
      'name', btrim(coalesce(exercise_item->>'nombre', '')),
      'targetMuscle', btrim(coalesce(exercise_item->>'musculoObjetivo', '')),
      'equipment', btrim(coalesce(exercise_item->>'equipamiento', '')),
      'targetSets', exercise_item->>'seriesObjetivo',
      'targetReps', exercise_item->>'repeticionesObjetivo',
      'notes', exercise_item->>'notas'
    )
  ), '[]'::jsonb)
  into exercises_payload
  from jsonb_array_elements(coalesce(p_routine->'ejercicios', '[]'::jsonb))
  with ordinality as payload(exercise_item, exercise_order);

  return public.save_routine_with_exercises(
    p_routine->>'titulo',
    p_routine->>'descripcion',
    exercises_payload
  );
end;
$$;

grant execute on function public.save_routine_with_exercises(text, text, jsonb) to authenticated;
grant execute on function public.save_ai_routine(jsonb) to authenticated;

commit;


-- END supabase/migrations/20260706_consolidate_save_routine_rpc.sql

-- BEGIN supabase/migrations/20260706_harden_workout_logs_routine_ownership.sql

-- RLS edge case: the insert/update policies on workout_logs only checked
-- `auth.uid() = user_id`, never that `routine_id` (when set) actually belongs to
-- that same user. A client could bypass the UI and directly call
-- `supabase.from('workout_logs').insert/update({ user_id: me, routine_id: <someone
-- else's routine id> })`. This doesn't leak the other routine's data (routines and
-- routine_exercises stay scoped to their owner via their own RLS), but it lets a
-- user misattribute a workout to a routine they don't own. Tightened both policies
-- to require routine_id to be null or owned by auth.uid(), mirroring the check
-- routine_exercises already does for its own routine_id.

begin;

drop policy if exists "Users can create own workout logs" on public.workout_logs;
create policy "Users can create own workout logs"
on public.workout_logs for insert
to authenticated
with check (
  auth.uid() = user_id
  and (
    routine_id is null
    or exists (
      select 1 from public.routines
      where routines.id = workout_logs.routine_id
        and routines.user_id = auth.uid()
    )
  )
);

drop policy if exists "Users can update own workout logs" on public.workout_logs;
create policy "Users can update own workout logs"
on public.workout_logs for update
to authenticated
using (auth.uid() = user_id)
with check (
  auth.uid() = user_id
  and (
    routine_id is null
    or exists (
      select 1 from public.routines
      where routines.id = workout_logs.routine_id
        and routines.user_id = auth.uid()
    )
  )
);

commit;


-- END supabase/migrations/20260706_harden_workout_logs_routine_ownership.sql

