-- BEGIN supabase/migrations/20260714_add_ai_generations.sql

-- Fase vNext 10 (ROADMAP.md): traceability for AI-generated content — model,
-- prompt/schema version, input/output, latency, success/error — so a bad prompt
-- can be identified and compared against prior versions. Only the 3 AI routes
-- that exist today are valid `type` values; extend the CHECK when new ones ship
-- (program_week_generation, exercise_substitution, coach_recommendation).

begin;

create table public.ai_generations (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references public.profiles(id) on delete set null,
  type text not null check (type in ('routine_generation', 'routine_regeneration', 'workout_insight')),
  model text not null,
  prompt_version text not null,
  schema_version text not null,
  input jsonb,
  output jsonb,
  latency_ms integer,
  success boolean not null default false,
  error text,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

alter table public.ai_generations enable row level security;

create policy "Users can read own ai generations"
on public.ai_generations for select
to authenticated
using (auth.uid() = user_id);

create policy "Users can create own ai generations"
on public.ai_generations for insert
to authenticated
with check (auth.uid() = user_id);

commit;


-- END supabase/migrations/20260714_add_ai_generations.sql

-- BEGIN supabase/migrations/20260715_add_exercise_catalog_curation.sql

-- Fase vNext 4, resto (ROADMAP.md): curated exercise catalog fields (canonical
-- name, aliases, movement pattern, difficulty, verified flag) plus a minimal
-- admin flag so /admin/exercises can exist without opening the shared global
-- catalog to any authenticated user. There is no admin concept anywhere else in
-- this app yet — profiles.is_admin defaults to false for everyone; the first
-- admin has to be flipped by hand (e.g. via the Supabase SQL editor), same as
-- any bootstrap-admin problem.

begin;

alter table public.profiles
  add column if not exists is_admin boolean not null default false;

alter table public.exercises
  add column if not exists canonical_name text,
  add column if not exists aliases text[] not null default '{}',
  add column if not exists movement_pattern text,
  add column if not exists difficulty text,
  add column if not exists is_verified boolean not null default false;

alter table public.exercises
  drop constraint if exists exercises_movement_pattern_check,
  add constraint exercises_movement_pattern_check check (
    movement_pattern is null or movement_pattern in (
      'squat', 'hinge', 'horizontal_push', 'vertical_push',
      'horizontal_pull', 'vertical_pull', 'lunge', 'carry',
      'core', 'isolation', 'conditioning', 'mobility'
    )
  );

alter table public.exercises
  drop constraint if exists exercises_difficulty_check,
  add constraint exercises_difficulty_check check (
    difficulty is null or difficulty in ('beginner', 'intermediate', 'advanced')
  );

-- Only admins can edit the global catalog (owner_id is null); nobody could
-- update `exercises` at all before this (20260706_restrict_direct_exercise_inserts.sql
-- removed the last direct-write policy). Personal exercises still have no update
-- path — no feature creates them yet.
create policy "Admins can update global exercises"
on public.exercises for update
to authenticated
using (
  owner_id is null
  and exists (select 1 from public.profiles where id = auth.uid() and is_admin)
)
with check (
  owner_id is null
  and exists (select 1 from public.profiles where id = auth.uid() and is_admin)
);

commit;


-- END supabase/migrations/20260715_add_exercise_catalog_curation.sql

-- BEGIN supabase/migrations/20260716_add_alias_matching.sql

-- Fase vNext 4, resto (ROADMAP.md): matches an incoming exercise name against the
-- curated `aliases` array too, not just an exact case-insensitive name match.
-- This is what actually closes the "Press banca" vs "Press de banca" vs "Barbell
-- bench press" duplication gap — but only once an admin has curated aliases via
-- /admin/exercises (20260715_add_exercise_catalog_curation.sql); until then this
-- is a no-op superset of the existing exact-match behavior.

begin;

create or replace function public._insert_routine_exercises(
  target_routine_id uuid,
  exercises_payload jsonb
)
returns void
language plpgsql
set search_path = public
as $$
declare
  exercise_payload jsonb;
  exercise_id uuid;
  exercise_name text;
  exercise_target_muscle text;
  exercise_equipment text;
  exercise_order integer := 0;
begin
  if exercises_payload is null or jsonb_typeof(exercises_payload) <> 'array' or jsonb_array_length(exercises_payload) = 0 then
    raise exception 'La rutina debe incluir al menos un ejercicio.';
  end if;

  for exercise_payload in select value from jsonb_array_elements(exercises_payload)
  loop
    exercise_order := exercise_order + 1;
    exercise_name := btrim(coalesce(exercise_payload->>'name', ''));
    exercise_target_muscle := btrim(coalesce(exercise_payload->>'targetMuscle', ''));
    exercise_equipment := btrim(coalesce(exercise_payload->>'equipment', ''));

    if exercise_name = '' then
      raise exception 'El ejercicio % no tiene nombre.', exercise_order;
    end if;

    select id into exercise_id
    from public.exercises
    where (
        lower(btrim(name)) = lower(btrim(exercise_name))
        or lower(btrim(exercise_name)) = any(select lower(btrim(alias)) from unnest(aliases) as alias)
      )
      and lower(btrim(target_muscle)) = lower(btrim(exercise_target_muscle))
      and lower(btrim(equipment)) = lower(btrim(exercise_equipment))
    limit 1;

    if exercise_id is null then
      begin
        insert into public.exercises (name, target_muscle, equipment)
        values (exercise_name, exercise_target_muscle, exercise_equipment)
        returning id into exercise_id;
      exception when unique_violation then
        select id into exercise_id
        from public.exercises
        where (
            lower(btrim(name)) = lower(btrim(exercise_name))
            or lower(btrim(exercise_name)) = any(select lower(btrim(alias)) from unnest(aliases) as alias)
          )
          and lower(btrim(target_muscle)) = lower(btrim(exercise_target_muscle))
          and lower(btrim(equipment)) = lower(btrim(exercise_equipment))
        limit 1;
      end;
    end if;

    if exercise_id is null then
      raise exception 'No se pudo crear o reutilizar el ejercicio %.', exercise_name;
    end if;

    insert into public.routine_exercises (
      routine_id,
      exercise_id,
      order_index,
      target_sets,
      target_reps,
      notes,
      rest_seconds,
      target_rpe,
      target_rir,
      tempo,
      movement_pattern,
      priority,
      progression_rule,
      substitution_criteria
    )
    values (
      target_routine_id,
      exercise_id,
      coalesce((exercise_payload->>'orderIndex')::integer, exercise_order),
      nullif(exercise_payload->>'targetSets', '')::integer,
      nullif(exercise_payload->>'targetReps', ''),
      nullif(exercise_payload->>'notes', ''),
      nullif(exercise_payload->>'restSeconds', '')::integer,
      nullif(exercise_payload->>'targetRpe', '')::numeric,
      nullif(exercise_payload->>'targetRir', '')::numeric,
      nullif(exercise_payload->>'tempo', ''),
      nullif(exercise_payload->>'movementPattern', ''),
      nullif(exercise_payload->>'priority', ''),
      nullif(exercise_payload->>'progressionRule', ''),
      nullif(exercise_payload->>'substitutionCriteria', '')
    );
  end loop;
end;
$$;

commit;


-- END supabase/migrations/20260716_add_alias_matching.sql

-- BEGIN supabase/migrations/20260717_add_offline_idempotency.sql

-- Idempotency columns for offline write support (vNext 14).
-- These nullable columns let the client assign a unique operation ID so the
-- API layer can detect duplicate inserts when retrying after a failed sync.
ALTER TABLE workout_logs ADD COLUMN IF NOT EXISTS client_operation_id text;

ALTER TABLE set_logs ADD COLUMN IF NOT EXISTS client_operation_id text;

ALTER TABLE readiness_logs ADD COLUMN IF NOT EXISTS client_operation_id text;


